from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import time

app = Flask(__name__)
es = Elasticsearch()

def rate_limit(max_requests, period):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            client_ip = request.remote_addr
            current_time = int(time.time())
            key = f"rate_limit:{client_ip}:{func.__name__}"
            
            with app.redis_client as redis:
                if redis.exists(key):
                    last_request_time = int(redis.get(key))
                    time_since_last_request = current_time - last_request_time
                    if time_since_last_request < period:
                        remaining_requests = max_requests - (time_since_last_request // period)
                        return jsonify({"error": "Too many requests", "remaining": remaining_requests}), 429
                
                redis.setex(key, period, current_time)
                redis.incr(key)
            
            return func(*args, **kwargs)
        return wrapper
    return decorator

@app.route('/api/search', methods=['GET'])
@rate_limit(max_requests=100, period=60)  # Allow 100 requests per minute
def search():
    keyword = request.args.get('q')
    if not keyword:
        return jsonify({"error": "Missing keyword"}), 400
    
    query = {
        "query": {
            "match": {
                "name": keyword
            }
        }
    }
    
    results = es.search(index="products", body=query)
    products = [hit['_source'] for hit in results['hits']['hits']]
    
    return jsonify(products)

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)